import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';

function App() {
  const [etapa, setEtapa] = useState('login'); // login, escolha, acao
  const [modo, setModo] = useState(''); // retirada ou devolucao
  const [codigo, setCodigo] = useState("");
  const [usuario, setUsuario] = useState(null);
  const [mensagem, setMensagem] = useState("Aguardando crachá...");
  const [carregando, setCarregando] = useState(false);
  const inputRef = useRef(null);

  // Mantém o foco no input para o leitor sempre funcionar
  useEffect(() => {
    inputRef.current?.focus();
  }, [etapa, modo]);

  const handleKeyPress = async (e) => {
    if (e.key === 'Enter') {
      // INTERROMPE o comportamento padrão do navegador (evita o erro do leitor)
      e.preventDefault(); 
      
      const valorLido = codigo.trim();
      if (!valorLido || carregando) return;

      console.log("Leitura detectada:", valorLido);
      setCarregando(true);

      if (etapa === 'login') {
        await realizarLogin(valorLido);
      } else if (etapa === 'acao') {
        await processarAcao(valorLido);
      }

      // Limpa o campo APÓS o processamento
      setCodigo("");
      setCarregando(false);
    }
  };

  const realizarLogin = async (codBarras) => {
    try {
      setMensagem("Buscando usuário...");
      const res = await axios.post('http://localhost:3001/login', { codBarras });
      setUsuario(res.data);
      setEtapa('escolha');
      setMensagem(`Olá, ${res.data.nome}! O que deseja fazer?`);
    } catch (err) {
      setMensagem("❌ Crachá não encontrado.");
      console.error(err);
    }
  };

  const processarAcao = async (ferramentacod) => {
    const url = modo === 'retirada' ? '/emprestimo/retirada' : '/emprestimo/devolucao';
    const dados = modo === 'retirada' 
      ? { usuarioId: usuario.id, ferramentacod } 
      : { ferramentacod };

    try {
      setMensagem("Processando no banco...");
      const res = await axios.post(`http://localhost:3001${url}`, dados);
      setMensagem(`✅ ${res.data}`);
      
      // Reseta o sistema para o próximo após 3 segundos
      setTimeout(() => {
        setEtapa('login');
        setUsuario(null);
        setModo('');
        setMensagem("Aguardando crachá...");
      }, 3000);
    } catch (err) {
      setMensagem("❌ Erro na operação. Tente novamente.");
      console.error(err);
    }
  };

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <img src="/logo-tsea.png" style={styles.logo} alt="logo" />
        <h1 style={styles.title}>TSEA - Rastreabilidade</h1>
      </header>
      
      <div style={styles.card}>
        <h2 style={{ color: carregando ? '#777' : '#002d62' }}>{mensagem}</h2>

        {etapa === 'escolha' && (
          <div style={styles.btnContainer}>
            <button 
              onClick={() => { setModo('retirada'); setEtapa('acao'); setMensagem("Bipe a FERRAMENTA para RETIRADA"); }} 
              style={{...styles.button, backgroundColor: '#0055ff'}}
            >
              PEGAR FERRAMENTA
            </button>
            <button 
              onClick={() => { setModo('devolucao'); setEtapa('acao'); setMensagem("Bipe a FERRAMENTA para DEVOLUÇÃO"); }} 
              style={{...styles.button, backgroundColor: '#28a745'}}
            >
              ENTREGAR FERRAMENTA
            </button>
          </div>
        )}

        {(etapa === 'login' || etapa === 'acao') && (
          <div style={styles.inputWrapper}>
            <input 
              ref={inputRef}
              value={codigo} 
              onChange={(e) => setCodigo(e.target.value)} 
              onKeyDown={handleKeyPress} 
              placeholder="Aguardando scanner..." 
              style={styles.input}
              disabled={carregando}
            />
            {carregando && <p style={styles.loadingText}>Processando...</p>}
          </div>
        )}

        {usuario && etapa !== 'login' && (
          <div style={styles.footerInfo}>
            <p>Sessão ativa: <strong>{usuario.nome}</strong></p>
          </div>
        )}
      </div>
    </div>
  );
}

const styles = {
  container: { textAlign: 'center', marginTop: '50px', fontFamily: 'Arial', backgroundColor: '#f4f7f9', minHeight: '100vh', padding: '20px' },
  header: { marginBottom: '30px' },
  logo: { width: '180px', marginBottom: '10px' },
  title: { color: '#002d62', fontSize: '28px' },
  card: { padding: '40px', border: 'none', display: 'inline-block', borderRadius: '15px', backgroundColor: 'white', boxShadow: '0 4px 15px rgba(0,0,0,0.1)', minWidth: '400px' },
  input: { padding: '15px', fontSize: '20px', width: '300px', border: '2px solid #0055ff', textAlign: 'center', borderRadius: '8px', outline: 'none' },
  button: { padding: '20px', fontSize: '18px', color: 'white', border: 'none', borderRadius: '8px', margin: '10px', cursor: 'pointer', fontWeight: 'bold', width: '220px' },
  btnContainer: { display: 'flex', flexDirection: 'column', alignItems: 'center' },
  inputWrapper: { marginTop: '20px' },
  loadingText: { color: '#0055ff', fontSize: '14px', fontWeight: 'bold' },
  footerInfo: { marginTop: '30px', borderTop: '1px solid #eee', paddingTop: '10px', color: '#666' }
};

export default App;
